func appStatusClass(status string) string {
	switch status {
	case "running":
		return "px-2 py-0.5 text-xs rounded-full bg-green-900/40 text-green-400"
	case "building", "pushing", "deploying":
		return "px-2 py-0.5 text-xs rounded-full bg-blue-900/40 text-blue-400 animate-pulse"
	case "error":
		return "px-2 py-0.5 text-xs rounded-full bg-red-900/40 text-red-400"
	case "stopped":
		return "px-2 py-0.5 text-xs rounded-full bg-neutral-700 text-neutral-400"
	default:
		return "px-2 py-0.5 text-xs rounded-full bg-neutral-700 text-neutral-500"
	}
}

func appIsBuilding(status string) bool {
	switch status {
	case "building", "pushing", "deploying":
		return true
	}
	return false
}

