// ── Go helpers ────────────────────────────────────────────────────────────────

func shortRepoURL(u string) string {
	u = strings.TrimPrefix(u, "https://")
	u = strings.TrimPrefix(u, "http://")
	u = strings.TrimSuffix(u, ".git")
	return u
}

func shortImageRef(ref string) string {
	if ref == "" {
		return "—"
	}
	parts := strings.SplitN(ref, "/", 3)
	if len(parts) == 3 {
		return parts[1] + "/" + parts[2]
	}
	return ref
}

func formTitle(name string, isEdit bool) string {
	if isEdit {
		return "Edit App: " + name
	}
	return "New Docker App"
}

func formAction(id string, isEdit bool) string {
	if isEdit {
		return "/docker/apps/" + id
	}
	return "/docker/apps"
}

func regPassPlaceholder(isEdit bool) string {
	if isEdit {
		return "leave blank to keep existing"
	}
	return "password or access token"
}

